import{_ as d,o as e,c as a,ag as r}from"./chunks/framework.8qlNDhri.js";const g=JSON.parse('{"title":"模型更新日志","description":"Voxplore AI 模型版本变更历史、TTS/ASR/LLM 更新追踪。","frontmatter":{"title":"模型更新日志","description":"Voxplore AI 模型版本变更历史、TTS/ASR/LLM 更新追踪。"},"headers":[],"relativePath":"model-updates.md","filePath":"model-updates.md","lastUpdated":1776522580000}'),o={name:"model-updates.md"};function h(n,t,l,s,i,b){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="模型更新日志" tabindex="-1">模型更新日志 <a class="header-anchor" href="#模型更新日志" aria-label="Permalink to &quot;模型更新日志&quot;">​</a></h1><p>本文档追踪 Voxplore 各 AI 模型层的版本变更，帮助你了解每个版本的能力变化和配置差异。</p><hr><h2 id="_2026-04-模型版本总览" tabindex="-1">2026-04 模型版本总览 <a class="header-anchor" href="#_2026-04-模型版本总览" aria-label="Permalink to &quot;2026-04 模型版本总览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模型层</th><th>当前版本</th><th>状态</th></tr></thead><tbody><tr><td><strong>LLM（解说生成）</strong></td><td>DeepSeek-V3.2</td><td>✅ 推荐</td></tr><tr><td><strong>视频理解</strong></td><td>Qwen2.5-VL (7B)</td><td>✅ 推荐</td></tr><tr><td><strong>ASR（语音识别）</strong></td><td>SenseVoice</td><td>✅ 推荐</td></tr><tr><td><strong>TTS（配音合成）</strong></td><td>Edge-TTS 7.2.8</td><td>✅ 推荐</td></tr><tr><td><strong>音色克隆</strong></td><td>F5-TTS</td><td>🔶 可选</td></tr></tbody></table><hr><h2 id="v3-6-0-—-2026-04-11" tabindex="-1">v3.6.0 — 2026-04-11 <a class="header-anchor" href="#v3-6-0-—-2026-04-11" aria-label="Permalink to &quot;v3.6.0 — 2026-04-11&quot;">​</a></h2><h3 id="架构升级" tabindex="-1">架构升级 <a class="header-anchor" href="#架构升级" aria-label="Permalink to &quot;架构升级&quot;">​</a></h3><table tabindex="0"><thead><tr><th>变更类型</th><th>内容</th></tr></thead><tbody><tr><td><strong>类型安全</strong></td><td><code>models.py</code> Any: 89→0，Pydantic v2 替换 dataclass，7个新子类型</td></tr><tr><td><strong>Provider 抽象</strong></td><td>新建 <code>provider_models.py</code>（Pydantic 模型），统一 LLM Provider 接口</td></tr><tr><td><strong>Bug 修复</strong></td><td>Hunyuan / Doubao <code>usage</code> 字段缺失问题修复</td></tr></tbody></table><blockquote><p><strong>Voxplore v3.6.0 推荐默认配置不变</strong>：DeepSeek-V3.2 + Qwen2.5-VL + Edge-TTS。</p></blockquote><hr><h2 id="v3-5-0-—-2026-04-10" tabindex="-1">v3.5.0 — 2026-04-10 <a class="header-anchor" href="#v3-5-0-—-2026-04-10" aria-label="Permalink to &quot;v3.5.0 — 2026-04-10&quot;">​</a></h2><h3 id="ui-全面重构" tabindex="-1">UI 全面重构 <a class="header-anchor" href="#ui-全面重构" aria-label="Permalink to &quot;UI 全面重构&quot;">​</a></h3><table tabindex="0"><thead><tr><th>变更类型</th><th>内容</th></tr></thead><tbody><tr><td><strong>OKLCH 色彩系统</strong></td><td>UI 全面迁移至 OKLCH 色彩空间，设计一致性提升</td></tr><tr><td><strong>OutCubic 缓动动画</strong></td><td>动画曲线规范化，交互体验更专业</td></tr><tr><td><strong>创作向导重构</strong></td><td>3 步向导页面全新设计，StageCard 组件动画修复</td></tr><tr><td><strong>WizardPage 信号管理</strong></td><td>修复信号重复绑定、StepPipeline 断开旧连接问题</td></tr></tbody></table><blockquote><p>设计规范与 Voxplore Design System v2 对齐。</p></blockquote><hr><h2 id="v3-4-0-—-2026-04-09" tabindex="-1">v3.4.0 — 2026-04-09 <a class="header-anchor" href="#v3-4-0-—-2026-04-09" aria-label="Permalink to &quot;v3.4.0 — 2026-04-09&quot;">​</a></h2><h3 id="品牌与产品定位重构" tabindex="-1">品牌与产品定位重构 <a class="header-anchor" href="#品牌与产品定位重构" aria-label="Permalink to &quot;品牌与产品定位重构&quot;">​</a></h3><table tabindex="0"><thead><tr><th>变更类型</th><th>内容</th></tr></thead><tbody><tr><td><strong>品牌重命名</strong></td><td>Voxplore → <strong>Voxplore</strong>，视觉识别系统全面更新</td></tr><tr><td><strong>产品定位聚焦</strong></td><td>裁剪全部冗余功能（MashupMaker / BeatSyncMaker / CommentaryMaker / BatchProcessor），只保留 <strong>MonologueMaker</strong> 核心——AI 第一人称视频解说</td></tr><tr><td><strong>OKLCH 设计系统</strong></td><td>首次引入 OKLCH 色彩系统，替代原有 HSL 配色</td></tr></tbody></table><hr><h2 id="v3-3-0-—-2026-04-08" tabindex="-1">v3.3.0 — 2026-04-08 <a class="header-anchor" href="#v3-3-0-—-2026-04-08" aria-label="Permalink to &quot;v3.3.0 — 2026-04-08&quot;">​</a></h2><h3 id="性能优化" tabindex="-1">性能优化 <a class="header-anchor" href="#性能优化" aria-label="Permalink to &quot;性能优化&quot;">​</a></h3><table tabindex="0"><thead><tr><th>变更类型</th><th>内容</th></tr></thead><tbody><tr><td><strong>Scene Detection</strong></td><td>视频场景检测算法优化，处理速度提升</td></tr></tbody></table><hr><h2 id="tts-引擎版本详情" tabindex="-1">TTS 引擎版本详情 <a class="header-anchor" href="#tts-引擎版本详情" aria-label="Permalink to &quot;TTS 引擎版本详情&quot;">​</a></h2><h3 id="edge-tts" tabindex="-1">Edge-TTS <a class="header-anchor" href="#edge-tts" aria-label="Permalink to &quot;Edge-TTS&quot;">​</a></h3><table tabindex="0"><thead><tr><th>版本</th><th>日期</th><th>变更</th></tr></thead><tbody><tr><td>7.2.8</td><td>2026-03</td><td><strong>当前版本</strong>，多音色优化，中文自然度提升</td></tr><tr><td>7.0.0</td><td>2026-01</td><td>正式支持情感控制参数</td></tr></tbody></table><p><strong>推荐音色配置：</strong></p><table tabindex="0"><thead><tr><th>场景</th><th>音色</th><th>风格</th></tr></thead><tbody><tr><td>治愈风格</td><td><code>zh-CN-Xiaoxiao</code></td><td>女声，温暖清晰</td></tr><tr><td>悬疑风格</td><td><code>zh-CN-Yunxi</code></td><td>男声，低沉留白</td></tr><tr><td>励志风格</td><td><code>zh-CN-Yunyang</code></td><td>男声，专业有力</td></tr><tr><td>浪漫风格</td><td><code>zh-CN-Xiaoyi</code></td><td>女声，细腻柔和</td></tr></tbody></table><h3 id="f5-tts-可选·音色克隆" tabindex="-1">F5-TTS（可选·音色克隆） <a class="header-anchor" href="#f5-tts-可选·音色克隆" aria-label="Permalink to &quot;F5-TTS（可选·音色克隆）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>版本</th><th>日期</th><th>变更</th></tr></thead><tbody><tr><td>latest</td><td>2026-03</td><td>零样本音色克隆，15-30秒参考音频即可克隆任意音色</td></tr></tbody></table><blockquote><p>⚠️ F5-TTS 需要独立安装，详见<a href="./guide/installation.html#f5-tts-音色克隆">安装指南</a>。</p></blockquote><hr><h2 id="asr-模型对比" tabindex="-1">ASR 模型对比 <a class="header-anchor" href="#asr-模型对比" aria-label="Permalink to &quot;ASR 模型对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模型</th><th>部署</th><th>中文精度</th><th>说话人分离</th><th>推荐场景</th></tr></thead><tbody><tr><td><strong>SenseVoice</strong></td><td>本地</td><td>⭐⭐⭐⭐⭐</td><td>✅</td><td>Voxplore 默认，精度的中文 ASR</td></tr><tr><td>Whisper</td><td>本地</td><td>⭐⭐⭐⭐</td><td>❌</td><td>多语言内容</td></tr><tr><td>云端 ASR</td><td>API</td><td>⭐⭐⭐⭐⭐</td><td>✅</td><td>需要最高精度且不介意上传</td></tr></tbody></table><hr><h2 id="模型选择快速参考" tabindex="-1">模型选择快速参考 <a class="header-anchor" href="#模型选择快速参考" aria-label="Permalink to &quot;模型选择快速参考&quot;">​</a></h2><table tabindex="0"><thead><tr><th>预算</th><th>LLM（解说生成）</th><th>视频理解</th><th>TTS</th><th>ASR</th></tr></thead><tbody><tr><td>免费</td><td>DeepSeek-V3.2</td><td>Qwen2.5-VL（本地）</td><td>Edge-TTS</td><td>SenseVoice</td></tr><tr><td>&lt;$5/月</td><td>DeepSeek-V3.2</td><td>Qwen2.5-VL（API）</td><td>Edge-TTS</td><td>SenseVoice</td></tr><tr><td>$5-50/月</td><td>GPT-5.4</td><td>GPT-5.4 Vision</td><td>Edge-TTS</td><td>SenseVoice</td></tr><tr><td>&gt;$50/月</td><td>Claude Opus 4.6</td><td>GPT-5.4 Vision</td><td>OpenAI TTS</td><td>SenseVoice</td></tr></tbody></table><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="./ai-models.html">AI 模型配置</a> — 各模型详细说明与配置指南</li><li><a href="./guide/installation.html">安装配置</a> — F5-TTS 等可选模型安装步骤</li><li><a href="./guide/troubleshooting.html">疑难排查</a> — 模型相关问题解决方案</li></ul>',41)])])}const u=d(o,[["render",h]]);export{g as __pageData,u as default};
